Define the two index functions
# Rescaling function for stringy05
rescale_stringy05 &lt;- function(z, n) {
  lb &lt;- 0.05 + 3.86 / sqrt(n)
  pmax(0, (z - lb) / (1 - lb))
}

stringy05_raw &lt;- function(mat) {
  cassowaryr::sc_stringy05(mat[, 1], mat[, 2])
}

stringy05_rescaled &lt;- function(mat) {
  z &lt;- cassowaryr::sc_stringy05(mat[, 1], mat[, 2])
  rescale_stringy05(z, nrow(mat))
}

Adding stringy05 as a projection pursuit index
stringy05 &lt;- function() {
  function(mat) {
    cassowaryr::sc_stringy05(mat[, 1], mat[, 2])
  }
}
With this structure, I can use the index inside a guided tour:
guided_tour(stringy05())

Why rescaling is needed
While exploring the behaviour of the stringy05 index, I found that it does not necessarily return values close to zero for bivariate Gaussian data. This is important because, in high-dimensional data, many random projections can look approximately Gaussian. If the raw index gives these noise-like projections nonzero scores, the guided tour may spend time moving toward noisy views instead of real stringy patterns.
To address this, I estimated the 95th percentile of the noise distribution of stringy05 under bivariate Gaussian data. This gives a sample-size-dependent lower bound for values that can be expected from noise alone. I then used this threshold to rescale the index.
The rescaling function is:
rescale_stringy05 &lt;- function(z, n) {
  lb &lt;- 0.05 + 3.86 / sqrt(n)
  pmax(0, (z - lb) / (1 - lb))
}
Here, z is the raw stringy05 value and n is the sample size. Values below the estimated noise threshold are pushed to zero. Values above the threshold are rescaled so that the index focuses more on projections with stronger evidence of real stringy structure.
The updated index includes an option to use this rescaling:
stringy05 &lt;- function(rescale = FALSE) {
  function(mat) {
    z &lt;- cassowaryr::sc_stringy05(mat[, 1], mat[, 2])

    if (rescale) {
      z &lt;- rescale_stringy05(z, nrow(mat))
    }

    z
  }
}
Now I can use either the raw index:
guided_tour(stringy05())
or the rescaled version:
guided_tour(stringy05(rescale = TRUE))
The rescaled version is useful because it reduces the influence of noise-like Gaussian projections. This should help the optimization focus on projections that contain stronger and more meaningful stringy patterns.

Original outlier-removal idea
The outlier-removal function in cassowaryr returns a final delvor object after the iterative removal process has stopped.
outlier_removal &lt;- function(xy){
  # remove outliers iteratively (based on "Scagnostics Distributions" paper)
  repeat {
    # Get del, MST and weights
    del &lt;- alphahull::delvor(xy)
    weights &lt;- gen_edge_lengths(del)
    mst &lt;- gen_mst(del, weights)
    mst_weights &lt;- igraph::E(mst)$weight

    # get outliers
    outliers &lt;- outlying_identify(mst, mst_weights)
    # if no outliers, just return current del
    if(is.null(outliers)){
      return(del)
    } else{
      # otherwise we remove outliers and recompute
      xy &lt;- xy[-outliers,]
    }
  }
}
This is not one-step trimming. The repeat loop has been used so that after points are removed, the graph is recomputed and outlier detection is applied again.
However, this function does not directly return the removed points. It only returns the final Delaunay triangulation. Therefore, to identify the removed observations without changing the function, I compare the original coordinates with the coordinates remaining in final_del$x.

Helper function for comparing before and after
Because the original function returns only the final del object, I use the coordinates stored in final_del$x to identify which original observations were kept.


Code
make_key &lt;- function(x, y) {
  paste(signif(x, 17), signif(y, 17), sep = "__")
}

find_removed_points &lt;- function(xy_tbl) {

  xy_mat &lt;- xy_tbl |&gt;
    dplyr::select(x, y) |&gt;
    as.matrix()

  final_del &lt;- cassowaryr:::outlier_removal(xy_mat)

  kept_tbl &lt;- final_del$x |&gt;
    as_tibble(.name_repair = "minimal") |&gt;
    set_names(c("x", "y")) |&gt;
    mutate(key = make_key(x, y))

  xy_tbl |&gt;
    mutate(
      key = make_key(x, y),
      status = if_else(key %in% kept_tbl$key, "Kept", "Removed")
    ) |&gt;
    dplyr::select(-key)
}

Generate 10 bivariate Gaussian samples
Next, I repeat the same process for 10 independently generated bivariate Gaussian datasets. Again, I do not add artificial outliers.


Code
generate_gaussian_sample &lt;- function(sample_id, n = 250) {

  tibble(
    x = rnorm(n, mean = 0, sd = 1),
    y = rnorm(n, mean = 0, sd = 1)
  ) |&gt;
    mutate(
      sample_id = sample_id,
      id = row_number(),
      point_type = "gaussian"
    )
}

set.seed(452)

gaussian_samples &lt;- map_dfr(
  1:10,
  generate_gaussian_sample,
  n = n
)

Add controlled outliers to the same Gaussian datasets
Now I add artificial outliers to the same 10 Gaussian datasets. The Gaussian points are unchanged. This means any difference in which Gaussian points are removed must be caused by the presence of the added outliers.
I use a stepwise design:

clean: no added outliers
plus_1: one added outlier
plus_3: three added outliers
plus_5: five added outliers



Code
outlier_bank &lt;- tibble(
  outlier_number = 1:5,
  x = c(3.8, -3.8, 4.5, -4.5, 0),
  y = c(3.8,  3.8, -4.5, -4.5, 5.0)
)

scenario_info &lt;- tibble(
  outlier_level = c("clean", "plus_1", "plus_3", "plus_5"),
  n_added = c(0, 1, 3, 5)
)

create_scenario_data &lt;- function(sample_id_value, outlier_level, n_added) {

  base_data &lt;- gaussian_samples |&gt;
    filter(sample_id == sample_id_value) |&gt;
    mutate(
      outlier_level = outlier_level,
      point_type = "gaussian"
    )

  if (n_added == 0) {
    return(base_data)
  }

  added_outliers &lt;- outlier_bank |&gt;
    slice_head(n = n_added) |&gt;
    transmute(
      x = x,
      y = y,
      sample_id = sample_id_value,
      id = n + row_number(),
      point_type = "added_outlier",
      outlier_level = outlier_level
    )

  bind_rows(base_data, added_outliers)
}

experiment_data &lt;- tidyr::expand_grid(
  sample_id = unique(gaussian_samples$sample_id),
  scenario_info
) |&gt;
  pmap_dfr(
    \(sample_id, outlier_level, n_added) {
      create_scenario_data(sample_id, outlier_level, n_added)
    }
  ) |&gt;
  mutate(
    outlier_level = factor(
      outlier_level,
      levels = c("clean", "plus_1", "plus_3", "plus_5")
    )
  )

Apply outlier removal at each sample size
I use the same comparison approach as before. The original outlier_removal() function is not changed. I compare the original points with the points remaining in the final Delaunay object.


